// Time:  O(n)
// Space: O(1)

// array
class Solution {
public:
    int minOperations(vector<int>& nums) {
        int result = 0;
        for (int i = 0; i + 1 < size(nums); ++i) {
            if (nums[i] != nums[i + 1]) {
                ++result;
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(1)

# array
class Solution(object):
    def minOperations(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        return sum(nums[i] != nums[i+1] for i in xrange(len(nums)-1))
